// Fan out: one item per endpoint to ping.
const rows = $input.item.json;
const list = Array.isArray(rows) ? rows : [];
return list.map(function (r) { return { json: r }; });

// Classify ping result vs the endpoint's expected_status_code + timeout.
// $('Fan Out') and $('Ping Endpoint') items are paired by index.
const endpoint = $('Fan Out').itemMatching($itemIndex).json;
const resp = $input.item.json || {};
const start = $execution && $execution.startedAt ? new Date($execution.startedAt).getTime() : Date.now();
let status_code = null;
let status = 'unknown';
let last_error = null;
let response_time_ms = 0;

if (resp && resp.error) {
  last_error = String(resp.error.message || resp.error.code || resp.error);
  status = 'down';
  status_code = resp.error.statusCode || null;
} else if (resp && (resp.statusCode || resp.status)) {
  status_code = resp.statusCode || resp.status;
  response_time_ms = resp.headers && resp.headers['x-response-time-ms'] ? parseInt(resp.headers['x-response-time-ms']) : 0;
  if (status_code >= 200 && status_code < 400) status = 'up';
  else if (status_code >= 500) { status = 'down'; last_error = 'HTTP ' + status_code; }
  else { status = 'degraded'; last_error = 'HTTP ' + status_code; }
} else if (resp && resp.body !== undefined) {
  status = 'up';
  status_code = 200;
} else {
  status = 'unknown';
  last_error = 'No response data';
}

return { json: {
  p_endpoint_name:     endpoint.endpoint_name,
  p_endpoint_url:      endpoint.endpoint_url,
  p_endpoint_category: endpoint.endpoint_category,
  p_status_code:       status_code,
  p_response_time_ms:  response_time_ms,
  p_status:            status,
  p_last_error:        last_error
} };

const results = $('Classify Result').all().map(function (i) { return i.json; });
const counts = { up: 0, down: 0, degraded: 0, unknown: 0 };
results.forEach(function (r) { counts[r.p_status] = (counts[r.p_status] || 0) + 1; });
return { json: { ok: true, endpoints_checked: results.length, counts: counts } };
